<#\n.SYNOPSIS\n  GLM Coding Helper Lite — 打包工具\n  用 PyInstaller 将后端打包为单个 exe，开箱即用\n\n.USAGE\n  .\build_package.ps1                   # 打包（生产，单文件 exe ~400MB）\n  .\build_package.ps1 -Debug            # 打包 + 保留构建日志\n\n注意事项:\n  - 构建输出约 400MB + 模型数据（嵌入 exe 内部）\n  - 需要本机已安装所有依赖（venv 已 pip install -r requirements.txt）\n  - 用开发机打包一次，把 exe 发给其它电脑就行\n  - 其它电脑**不需要**装 Python / 任何依赖\n#>\n\nparam([switch]$Debug)\n\n$Root     = Split-Path -Parent $MyInvocation.MyCommand.Path\n$DistDir  = Join-Path $Root "dist"\n$BuildDir = Join-Path $Root "build"\n$LogFile  = Join-Path $Root "pyinstaller-build.log"\n\n$ErrorActionPreference = "Continue"\n\n# 出错时暂停以便看到错误信息\ntrap { Write-Host "`n[按任意键退出...]" -ForegroundColor Red; $null = $Host.UI.RawUI.ReadKey("NoEcho,IncludeKeyDown"); exit 1 }\n\n# ── 颜色 ───────────────────────────────────────────────────────────────────\n$G = "Green"; $Y = "Yellow"; $C = "Cyan"; $R = "Red"\n\nfunction Color($clr, $txt) { Write-Host $txt -ForegroundColor $clr }\n\n# ── 检测环境 ───────────────────────────────────────────────────────────────\nColor $C "╔════════════════════════════════════════╗"\nColor $C "║    GLM Coding Helper Lite  打包工具      ║"\nColor $C "╚════════════════════════════════════════╝"\nWrite-Host ""\n\n# 0) UTF8 编码（防止中文日志乱码）\n[Console]::OutputEncoding = [System.Text.UTF8Encoding]::new($false)\n\n# 1) 系统可用内存检查（防止 PyInstaller 吃爆）\ntry {\n    $os = Get-CimInstance Win32_OperatingSystem\n    $availGB = [math]::Round($os.FreePhysicalMemory / 1MB, 1)\n    if ($availGB -lt 8) {\n        Color $R "[ERROR] 可用内存不足 8GB（当前 ${availGB}GB），打包过程中 ML 库会占用大量内存，请关闭其它程序后重试"\n        exit 1\n    }\n    Color $G "[OK] 可用内存: ${availGB}GB"\n} catch {\n    Color $Y "[WARN] 无法检测系统内存，跳过"\n}\n\n# 2) Python\n$python = Get-Command python -ErrorAction SilentlyContinue\nif (-not $python) {\n    Color $R "[ERROR] 未找到 Python，请先安装"\n    exit 1\n}\nColor $G "[OK] Python: $($python.Source)"\n\n# 2) 虚拟环境\n$venvPython = Join-Path $Root "venv\Scripts\python.exe"\nif (-not (Test-Path $venvPython)) {\n    Color $R "[ERROR] 未找到虚拟环境 (venv)，请先运行 setup.ps1"\n    exit 1\n}\nColor $G "[OK] venv: 已找到"\n\n# 3) PyInstaller\n$pyi = & $venvPython -c "import PyInstaller; print(PyInstaller.__version__)" 2>$null\nif (-not $pyi) {\n    Color $Y "[INFO] 安装 PyInstaller..."\n    & $venvPython -m pip install pyinstaller -q\n    if ($LASTEXITCODE -ne 0) {\n        Color $R "[ERROR] PyInstaller 安装失败"\n        exit 1\n    }\n    $pyi = & $venvPython -c "import PyInstaller; print(PyInstaller.__version__)"\n}\nColor $G "[OK] PyInstaller: $pyi"\n\n# 4) 检查关键依赖（用 pip list，不 import，避免加载 ML 库吃内存）\nColor $G "[CHECK] 验证必要包..."\n$pkgList = & $venvPython -m pip list --format=json 2>$null\nif ($LASTEXITCODE -ne 0 -or -not $pkgList) {\n    Color $R "[ERROR] 无法获取包列表，请检查 venv 是否完整"\n    exit 1\n}\n$pkgNames = ($pkgList | ConvertFrom-Json).name\n$required = @("paddleocr", "ultralytics", "Pillow", "numpy", "opencv-python")\n$missing = $required | Where-Object { $_ -notin $pkgNames }\nif ($missing.Count -gt 0) {\n    Color $R "[ERROR] 缺少依赖: $($missing -join ', ')"\n    exit 1\n}\nColor $G "[OK] 所有核心依赖已安装"\n\n# 5) 检查模型文件\n$modelPath = Join-Path $Root "models\weights\yolo-captcha-detector.pt"\nif (-not (Test-Path $modelPath)) {\n    Color $R "[ERROR] 未找到模型文件: $modelPath"\n    exit 1\n}\nColor $G "[OK] 模型文件: 已找到"\n\nWrite-Host ""\n\n# ── 清理旧构建 ─────────────────────────────────────────────────────────────\nif (Test-Path $DistDir) {\n    Color $Y "[CLEAN] 删除旧的 dist 目录..."\n    Remove-Item $DistDir -Recurse -Force -ErrorAction SilentlyContinue\n}\nif (Test-Path $BuildDir) {\n    Remove-Item $BuildDir -Recurse -Force -ErrorAction SilentlyContinue\n}\n\n# ── 生成编译信息 ────────────────────────────────────────────────────────────\n$version = & $venvPython --version\nColor $C "  Python:  $version"\nColor $C "  输出目录: $DistDir"\nColor $C "  输出文件: GLM-Lite.exe"\nColor $C "  Debug:   $Debug"\nWrite-Host ""\n\nColor $Y "═══════════════ 开始 PyInstaller 编译 ═══════════════"\nColor $Y "  这可能需要 10~30 分钟，请耐心等待..."\nWrite-Host ""\n\n$env:PYTHONIOENCODING = "utf-8"\n\n# ── 拼装 PyInstaller 参数 ──────────────────────────────────────────────────\n$pyiArgs = @(\n    "--clean",\n    "--log-level", "$(if ($Debug) { 'DEBUG' } else { 'INFO' })",\n    "--distpath", $DistDir,\n    "--workpath", $BuildDir,\n    "--specpath", $Root,\n    "-y",\n    "--onefile",\n    "--name", "GLM-Lite",\n    "--add-data", "$Root\backend;backend",\n    "--add-data", "$Root\models;models",\n    # VC++ 运行库 DLL（确保新电脑无需额外安装）\n    "--add-binary", "C:\Windows\System32\vcruntime140.dll;.",\n    "--add-binary", "C:\Windows\System32\vcruntime140_1.dll;.",\n    "--add-binary", "C:\Windows\System32\msvcp140.dll;.",\n    "--add-binary", "C:\Windows\System32\msvcp140_1.dll;.",\n    "--add-binary", "C:\Windows\System32\msvcp140_2.dll;.",\n    "--add-binary", "C:\Windows\System32\concrt140.dll;.",\n    "--add-binary", "C:\Windows\System32\vcruntime140_threads.dll;.",\n    # 显式声明隐式导入\n    "--hidden-import", "ultralytics",\n    "--hidden-import", "ultralytics.nn.tasks",\n    "--hidden-import", "paddleocr",\n    "--hidden-import", "paddle",\n    "--hidden-import", "paddle.nn",\n    "--hidden-import", "PIL",\n    "--hidden-import", "PIL.Image",\n    "--hidden-import", "PIL.ImageDraw",\n    "--hidden-import", "PIL.ImageFont",\n    "--hidden-import", "numpy",\n    "--hidden-import", "cv2",\n    # 排除不需要的\n    "--exclude-module", "tkinter",\n    "--exclude-module", "matplotlib",\n    "--exclude-module", "scipy",\n    "--exclude-module", "IPython",\n    # 入口脚本\n    (Join-Path $Root "glm-lite.py")\n)\n\n# ── 跑 PyInstaller ─────────────────────────────────────────────────────────\nColor $C " 日志: $LogFile"\nWrite-Host ""\n& $venvPython -m PyInstaller @pyiArgs 2>&1 | Tee-Object -FilePath $LogFile\n$exitCode = $LASTEXITCODE\n\nif ($Debug) {\n    # Debug 模式也显示日志尾部\n    Get-Content $LogFile -Tail 30 | ForEach-Object { Write-Host $_ -ForegroundColor DarkGray }\n}\n\nif ($exitCode -ne 0) {\n    Color $R "[ERROR] PyInstaller 编译失败！(exit code $exitCode)"\n    Color $Y "  查看完整日志: $LogFile"\n    exit 1\n}\n\n# ── 确认输出 ────────────────────────────────────────────────────────────────\n$exePath = Join-Path $DistDir "GLM-Lite.exe"\nif (-not (Test-Path $exePath)) {\n    Color $R "[ERROR] 编译完成但未找到输出文件!"\n    exit 1\n}\n\n$sizeMB = [math]::Round((Get-Item $exePath).Length / 1MB, 1)\n\nWrite-Host ""\nColor $G "═══════════════ 打包完成 ═══════════════"\nColor $G "  输出: $exePath"\nColor $G "  大小: $sizeMB MB"\nWrite-Host ""\nColor $Y "  把 GLM-Lite.exe 发给其它电脑即可使用"\nColor $Y "  目标电脑不需要安装 Python / 任何依赖!"\nWrite-Host ""\nColor $C "  使用方法（在新电脑上）:"\nColor $C "    1. 双击 GLM-Lite.exe"\nColor $C "    2. 在浏览器安装油猴脚本加载器 (Tampermonkey)"\nColor $C "    3. 安装 glm-lite.user.js"\nColor $C "    4. 访问目标网站即可自动验证"\nWrite-Host ""\nColor $C "  首次启动会:"\nColor $C "    - 自动检测 CPU 核心数"\nColor $C "    - 按需要启动 YOLO / PP-OCR Worker"\nColor $C "    - 打开 http://localhost:8888"\nWrite-Host ""\n\n# ── 清理构建缓存 ──\nColor $Y "[CLEAN] 删除 build 缓存..."\nRemove-Item $BuildDir -Recurse -Force -ErrorAction SilentlyContinue\n# 保留 spec 文件以便排查\n$specFile = Join-Path $Root "GLM-Lite.spec"\nif (Test-Path $specFile) {\n    Color $Y "  保留 spec 文件: GLM-Lite.spec"\n}\n\nexit 0\n